async function shareContent() {
  if (!navigator.share) {
    console.log('Web Share API非対応');
    return;
  }
  try {
    await navigator.share({
      title: 'ページタイトル',
      text: '共有するテキスト',
      url: 'https://example.com',
    });
    console.log('共有成功');
  } catch (err) {
    if (err.name !== 'AbortError') {
      console.error('共有失敗:', err);
    }
  }
}

